// ── Franchise / character / form metadata (drives the picker UI) ─────────
const FORM_LABEL: Record<string, string> = {
  base: 'Base', ssj: 'Super Saiyan', ssj2: 'Super Saiyan 2', ssj3: 'Super Saiyan 3',
  blue: 'Super Saiyan Blue', sage: 'Sage Mode', kurama: 'Kurama', sharingan: 'Sharingan',
}

export interface CharacterDef { label: string; forms: string[] }
export interface FranchiseDef { label: string; characters: Record<string, CharacterDef> }

export const FRANCHISES: Record<string, FranchiseDef> = {
  'dragon-ball': {
    label: 'Dragon Ball',
    characters: {
      goku: { label: 'Goku', forms: ['base', 'ssj', 'ssj2', 'ssj3', 'blue'] },
      vegeta: { label: 'Vegeta', forms: ['base', 'ssj', 'blue'] },
      gohan: { label: 'Gohan', forms: ['base', 'ssj'] },
    },
  },
  naruto: {
    label: 'Naruto',
    characters: {
      naruto: { label: 'Naruto', forms: ['base', 'sage', 'kurama'] },
      sasuke: { label: 'Sasuke', forms: ['base', 'sharingan'] },
      kakashi: { label: 'Kakashi', forms: ['base'] },
    },
  },
}

export const formLabel = (formId: string) => FORM_LABEL[formId] || formId

export function charStyleId(characterId: string, formId: string) {
  return `char:${characterId}:${formId}`
}
export function isCharacterStyle(style: string): boolean {
  return typeof style === 'string' && style.startsWith('char:')
}
export function parseCharStyle(style: string): { characterId: string; formId: string } {
  const [, characterId = '', formId = 'base'] = style.split(':')
  return { characterId, formId }
}
export function franchiseOfCharacter(characterId: string): string | undefined {
  return Object.keys(FRANCHISES).find((f) => characterId in FRANCHISES[f].characters)
}
export function characterSvg(style: string): string {
  const { characterId, formId } = parseCharStyle(style)
  const forms = ART[characterId]
  if (!forms) return ''
  return forms[formId] || forms.base || ''
}

// Drop-in real-image override. If a PNG exists at this same-origin path it
// replaces the SVG (see DiceBearAvatar → CharacterFace); otherwise the SVG shows.
export const CHARACTER_IMAGE_BASE = '/assets/vernon_project/frontend/characters'
export function characterImagePath(style: string): string {
  const { characterId, formId } = parseCharStyle(style)
  return `${CHARACTER_IMAGE_BASE}/${characterId}-${formId}.png`
}
export function allCharacterImageFiles(): string[] {
  const out: string[] = []
  for (const fr of Object.values(FRANCHISES))
    for (const [cid, c] of Object.entries(fr.characters))
      for (const f of c.forms) out.push(`${cid}-${f}.png`)
  return out
}
